1	// claim-office.ts
2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  material?: string;
10	  cursed?: boolean;
11	  enchantment?: number;
12	};
13	
14	type Damage = {
15	  itemType: string;
16	  amount: number;
17	};
18	
19	type Incident = {
20	  cause: string;
21	  damages: Damage[];
22	};
23	
24	type Step = {
25	  op: string;
26	  items?: Item[];
27	  policy?: number;
28	  incident?: Incident;
29	};
30	
31	type ScenarioInput = {
32	  customer: Customer;
33	  steps: Step[];
34	};
35	
36	type ScenarioOutput = {
37	  results: unknown[];
38	};
39	
40	const PROCESSING_FEE = 5;
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const CURSE_SURCHARGE_RATE = 0.5;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
45	const LOYALTY_YEARS_THRESHOLD = 2;
46	const LOYALTY_DISCOUNT_RATE = 0.2;
47	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
48	const COMPONENT_BLOCK_SIZE = 3;
49	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
50	const DEDUCTIBLE = 100;
51	const HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
52	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
53	const FULL_REIMBURSEMENT_RATE = 1;
54	const CAP_MULTIPLIER = 2;
55	
56	const BASE_PREMIUMS: Record<string, number> = {
57	  sword: 100,
58	  amulet: 60,
59	  staff: 80,
60	  potion: 40,
61	  rune: 25,
62	  moonstone: 25,
63	};
64	
65	const INSURANCE_VALUES: Record<string, number> = {
66	  sword: 1000,
67	  amulet: 600,
68	  rune: 250,
69	};
70	
71	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
72	
73	const isComponentBlock = (type: string, count: number): boolean =>
74	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
75	
76	const basePremiumFor = (type: string): number => {
77	  const basePremium = BASE_PREMIUMS[type];
78	  if (basePremium === undefined) {
79	    throw new Error(`Unknown item type: ${type}`);
80	  }
81	  return basePremium;
82	};
83	
84	const surchargeFor = (
85	  items: Item[],
86	  applies: (item: Item) => boolean,
87	  rate: number
88	): number =>
89	  items.reduce(
90	    (surcharge, item) =>
91	      applies(item) ? surcharge + basePremiumFor(item.type) * rate : surcharge,
92	    0
93	  );
94	
95	const isCursed = (item: Item): boolean => item.cursed === true;
96	
97	const hasEnchantmentAtLeast = (
98	  item: Item | undefined,
99	  threshold: number
100	): boolean => (item?.enchantment ?? 0) >= threshold;
101	
102	const isHighlyEnchanted = (item: Item): boolean =>
103	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
104	
105	const curseSurchargeFor = (items: Item[]): number =>
106	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
107	
108	const enchantmentSurchargeFor = (items: Item[]): number =>
109	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
110	
111	const groupBasePremium = (type: string, count: number): number =>
112	  isComponentBlock(type, count)
113	    ? COMPONENT_BLOCK_BASE_PREMIUM
114	    : count * basePremiumFor(type);
115	
116	const policyBaseFor = (items: Item[]): number => {
117	  const countsByType = new Map<string, number>();
118	  for (const item of items) {
119	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
120	  }
121	
122	  let policyBase = 0;
123	  for (const [type, count] of countsByType) {
124	    policyBase += groupBasePremium(type, count);
125	  }
126	  return policyBase;
127	};
128	
129	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
130	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
131	
132	const quotePremium = (
133	  items: Item[],
134	  customer: Customer,
135	  isFollowUp: boolean
136	): number => {
137	  const policyBase = policyBaseFor(items);
138	  const itemSurcharges =
139	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
140	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
141	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
142	    ? policyBase * LOYALTY_DISCOUNT_RATE
143	    : 0;
144	  const followUpDiscount = isFollowUp
145	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
146	    : 0;
147	  return Math.ceil(
148	    policyBase +
149	      itemSurcharges +
150	      firstInsuranceSurcharge -
151	      loyaltyDiscount -
152	      followUpDiscount +
153	      PROCESSING_FEE
154	  );
155	};
156	
157	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
158	
159	const insuranceSumFor = (items: Item[]): number =>
160	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
161	
162	const reimbursementRateFor = (damagedItem: Item | undefined): number =>
163	  hasEnchantmentAtLeast(damagedItem, HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD)
164	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
165	    : FULL_REIMBURSEMENT_RATE;
166	
167	const processClaim = (step: Step, steps: Step[]): unknown => {
168	  const policyItems = steps[step.policy!].items ?? [];
169	  const payoutCap = insuranceSumFor(policyItems) * CAP_MULTIPLIER;
170	  const payout = step.incident!.damages.reduce((sum, damage) => {
171	    const damagedItem = policyItems.find(
172	      (item) => item.type === damage.itemType
173	    );
174	    return sum + damage.amount * reimbursementRateFor(damagedItem) - DEDUCTIBLE;
175	  }, 0);
176	  return { payout, remainingCap: payoutCap - payout };
177	};
178	
179	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
180	  const results = input.steps.map((step, index) =>
181	    step.op === "claim"
182	      ? processClaim(step, input.steps)
183	      : {
184	          premium: quotePremium(
185	            step.items ?? [],
186	            input.customer,
187	            isFollowUpQuote(index)
188	          ),
189	        }
190	  );
191	  return { results };
192	};
