const payoutForDamage = (damage: Damage, policyItems: Item[]): number => {
  const damagedItem = policyItems.find(
    (item) => item.type === damage.itemType
  );
  return damage.amount * reimbursementRateFor(damagedItem) - DEDUCTIBLE;
};

const processClaim = (step: Step, steps: Step[]): unknown => {
  const policyItems = steps[step.policy!].items ?? [];
  const payoutCap = insuranceSumFor(policyItems) * CAP_MULTIPLIER;
  const payout = step.incident!.damages.reduce(
    (sum, damage) => sum + payoutForDamage(damage, policyItems),
    0
  );
  return { payout, remainingCap: payoutCap - payout };
};

type QuoteResult = {
  premium: number;
};

type ClaimResult = {
  payout: number;
  remainingCap: number;
};

type StepResult = QuoteResult | ClaimResult;

type ScenarioOutput = {
  results: StepResult[];
};
